var benchResults = ($.steps.researchModels.response.searchBenchmarks && $.steps.researchModels.response.searchBenchmarks.response) ? $.steps.researchModels.response.searchBenchmarks.response.results || [] : [];
var osResults = ($.steps.researchModels.response.searchOpenSource && $.steps.researchModels.response.searchOpenSource.response) ? $.steps.researchModels.response.searchOpenSource.response.results || [] : [];
var benchContext = '';
benchResults.slice(0, 8).forEach(function(r, i) {
  benchContext += (i + 1) + '. ' + (r.title || '') + '\n   ' + r.url + '\n   ' + (r.text || '').slice(0, 400) + '\n\n';
});
var osContext = '';
osResults.slice(0, 8).forEach(function(r, i) {
  osContext += (i + 1) + '. ' + (r.title || '') + '\n   ' + r.url + '\n   ' + (r.text || '').slice(0, 400) + '\n\n';
});
var totalSources = benchResults.length + osResults.length;
return { benchContext: benchContext, osContext: osContext, totalSources: totalSources };

let raw = $.steps.aiCompare.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':robot_face: LLM Comparison: ' + $.input.useCase.slice(0, 80), emoji: true } });
if (ai.recommendation) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':trophy: *Recommendation:* ' + ai.recommendation } });
}
blocks.push({ type: 'divider' });
var models = ai.models || [];
models.forEach(function(m, i) {
  var scores = m.scores || {};
  var scoreBar = function(val) {
    var filled = Math.round((val || 0) / 10);
    var empty = 10 - filled;
    var bar = '';
    for (var j = 0; j < filled; j++) bar += '=';
    for (var k = 0; k < empty; k++) bar += '-';
    return '[' + bar + '] ' + (val || 0) + '/100';
  };
  var typeEmoji = m.type === 'open-source' ? ':unlock:' : ':lock:';
  var modelText = typeEmoji + ' *' + (i + 1) + '. ' + m.name + '* (' + (m.type || 'unknown') + ')\n';
  modelText += '  Quality: ' + scoreBar(scores.quality) + '\n';
  modelText += '  Speed:   ' + scoreBar(scores.speed) + '\n';
  modelText += '  Cost:    ' + scoreBar(scores.cost) + '\n';
  modelText += '  Deploy:  ' + scoreBar(scores.deployment) + '\n';
  if (m.bestFor) modelText += '  _Best for: ' + m.bestFor + '_\n';
  if (m.pros && m.pros.length > 0) modelText += '  :thumbsup: ' + m.pros.join(', ') + '\n';
  if (m.cons && m.cons.length > 0) modelText += '  :thumbsdown: ' + m.cons.join(', ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: modelText } });
});
if (ai.comparisonNotes) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Notes:* ' + ai.comparisonNotes } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':mag: ' + $.steps.compileResearch.output.totalSources + ' sources researched via Exa + Claude AI' }] });
var fallback = 'LLM Comparison for ' + $.input.useCase + ': ' + models.length + ' models compared';
if (ai.text) fallback = ai.text.slice(0, 500);
return { blocks, fallback };
